use std::collections::HashMap; use crate::core::buffer::Buffer; use crate::core::events::{EditorEvent, EventListener}; pub struct EditorAPI { pub buffers: HashMap<String, Buffer>, pub active_buffer: String, pub listeners: Vec<Box<dyn EventListener>>, } impl EditorAPI { pub fn new(initial_name: &str) -> Self { let mut buffers = HashMap::new(); buffers.insert(initial_name.to_string(), Buffer::new()); Self { buffers, active_buffer: initial_name.to_string(), listeners: Vec::new() } } pub fn notify(&self, event: EditorEvent) { for listener in &self.listeners { listener.on_event(event.clone()); } } pub fn add_listener(&mut self, listener: Box<dyn EventListener>) { self.listeners.push(listener); } pub fn get_active_buffer(&mut self) -> &mut Buffer { self.buffers.get_mut(&self.active_buffer).unwrap() } }
impl EditorAPI { pub fn handle_keypress(&mut self, key: &str) { let buffer = self.get_active_buffer(); match key { "BACKSPACE" => { buffer.undo(); } _ => { buffer.insert_line(0, buffer.lines[0].len(), key); } } self.notify(EditorEvent::TextChanged); } }
